const rankDisplays = (records: PlayerRecordDataType[], rankField: keyof PlayerRecordDataType) => {
    const ranks = records.map((record) => record[rankField]);

    return ranks.map((rank, index) => {
        if (rank === null || rank === undefined) return '-';
        if (ranks[index - 1] === rank) return '';
        return ranks[index + 1] === rank ? `${rank}=` : `${rank}`;
    });
};

export const RecordsTable = ({ table, year, records }: Props) => {
    const rankField = rankFieldByTable[table];
    const scoreHeading = scoreHeadingByTable[table];
    const ranks = rankDisplays(records, rankField);

    return (
        <Flex direction="column" gap="md">
            <Table>
                <TableThead>
                    <TableTr>
                        <TableTh>Position</TableTh>
                        <TableTh>Player</TableTh>
                        <TableTh>{scoreHeading}</TableTh>
                    </TableTr>
                </TableThead>
                <TableTbody>
                    {records.map((record, index) => (
                        <TableTr key={record.id}>
                            <TableTd>
                                {ranks[index]}
                            </TableTd>
                            <TableTd>
                                <PlayerLink player={record.player} year={year} />
                            </TableTd>
                            <TableTd>
                                <TableScore table={table} playerRecord={record} />
                            </TableTd>
                        </TableTr>
                    ))}
                </TableTbody>
            </Table>
        </Flex>
    );
};

