interface RankDisplay {
    visible: string;
    hidden?: string;
}

const rankDisplays = (records: PlayerRecordDataType[], rankField: RankField): RankDisplay[] => {
    const ranks = records.map((record) => record[rankField]);

    return ranks.map((rank, index) => {
        if (rank === null || rank === undefined) return { visible: '-' };
        if (ranks[index - 1] === rank) return { visible: '', hidden: `${rank}` };
        return { visible: ranks[index + 1] === rank ? `${rank}=` : `${rank}` };
    });
};

